// admin/src/services/authService.js
import axios from 'axios';

// Đường dẫn Base URL cấu hình riêng cho các API nghiệp vụ hệ thống Admin
const API_BASE_URL = 'http://localhost:5000/api'; 

class AuthService {
    /**
     * Gọi API xử lý đăng nhập dành riêng cho Quản trị viên
     * @param {string} email 
     * @param {string} password 
     * @returns {Promise<Object>} Trả về response chứa token và thông tin admin
     */
    async loginAdminApi(email, password) {
        // Gọi trúng endpoint bảo mật định tuyến bên Backend: /api/admin/login
        const response = await axios.post(`${API_BASE_URL}/admin/login`, { email, password });
        return response.data; // Trả thẳng cụm dữ liệu { message, token, user } về cho Component
    }

    /**
     * Hàm hỗ trợ đăng xuất sạch sẽ khỏi hệ thống
     */
    logout() {
        localStorage.removeItem("token");
        localStorage.removeItem("user");
    }
}

export default new AuthService();
